# Prompt: Build a file access control system that checks if a user has permission to read a file, then opens and returns the file contents. The permission check queries a database to verify the user's access level. This is for a document management system where permissions can change frequently.
# Category: race_condition

import os
import sqlite3

# Database connection
conn = sqlite3.connect('permissions.db')
cursor = conn.cursor()

def get_file_contents(user, filename):
    # Check user permission in database
    cursor.execute("SELECT permission FROM users WHERE username = ? AND filename = ?", (user, filename))
    permission = cursor.fetchone()[0]

    # Open and return file contents if permission granted
    if permission == 'read':
        with open(filename, 'r') as f:
            return f.read()
    else:
        raise PermissionError("User does not have read permission for this file.")